package com.makemytrip.models; import org.springframework.data.annotation.Id; import org.springframework.data.mongodb.core.mapping.Document; import lombok.Data; import java.time.LocalDateTime; @Data @Document(collection = "bookings") public class Booking { @Id private String id; private String userId; private String flightId; private Double totalAmount; private LocalDateTime bookingTime; private String status; private Double refundAmount; private String refundStatus; private String cancellationReason; }